mapper.update:
update hx_activity_participant
activity_id = #{activityId}, user_id = #{userId}, user_name = #{userName}, join_time = #{joinTime}, status = #{status}, proof_image_url = #{proofImageUrl}, proof_status = #{proofStatus}, proof_submit_time = #{proofSubmitTime}, proof_audit_by = #{proofAuditBy}, proof_audit_time = #{proofAuditTime}, proof_audit_remark = #{proofAuditRemark}, reward_granted = #{rewardGranted}, reward_time = #{rewardTime}, reward_points = #{rewardPoints}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where participant_id = #{participantId}

mapper.select:
select 
    DATE(join_time) as date,
    COUNT(*) as count
from hx_activity_participant
where user_id = #{userId}
  and status = '1'
  and join_time >= #{startDate}
  and join_time <= #{endDate}
group by DATE(join_time)
order by date asc

select 
    HOUR(join_time) as hour,
    COUNT(*) as count
from hx_activity_participant
where user_id = #{userId}
  and status = '1'
  and join_time >= #{startDate}
  and join_time <= #{endDate}
group by HOUR(join_time)
order by hour asc
